merged = merged[merged['rating_f'].notnull()]

# per-book average
per_book = merged.groupby('book_id').agg(avg_rating=('rating_f','mean'), pub_year=('pub_year', lambda x: x.dropna().mode().iat[0] if x.dropna().size>0 else None)).reset_index()

# keep books with pub_year
per_book_with_year = per_book[per_book['pub_year'].notnull()].copy()

if per_book_with_year.empty:
    out = {'decade': None, 'average_rating': None, 'book_count': 0}
else:
