        best = decade_stats.sort_values(['decade_avg_rating','book_count','decade_start'], ascending=[False,False,True]).iloc[0]
        out = {'decade': best['decade'], 'average_rating': round(float(best['decade_avg_rating']),4), 'book_count': int(best['book_count'])}

print("__RESULT__:")
print(json.dumps(out))
